var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아래쪽에서 침식체들이 계속 나오고 있어.","JPN":"下から侵食体がどんどん出て来る。","ENG":"C.O.s keep appearing from below.","TWN":"侵蝕體不斷從下方出現。 "},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"지하층에 침식 쐐기가 있는 것 같네요.","JPN":"地下に侵食楔があるようです。","ENG":"It looks like there's a Corrupted Wedge underground.","TWN":"地下層好像有侵蝕釘。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"그래. 하지만 쐐기를 처리하려고 지금 지하로 향하는 건 자살행위나 다름없지.","JPN":"そうだ。だが、侵食楔を処理するために今地下に行くのは自殺行為に他ならない。","ENG":"Yeah. But heading down there to deal with the Wedge now would be suicide.","TWN":"是啊。但現在去地下室處理侵蝕釘不是自殺行為嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"들어왔던 길목은 침식체가 진을 치고 있어 돌파가 쉽지 않겠군.","JPN":"入って来た道は侵食体が陣を張っているから突破しづらい。","ENG":"The path we came through is now blocked by C.O.s, so breaking through won't be easy.","TWN":"進來的路口被侵蝕體佔據了，不好突破。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"그나마 개체 수가 적은 측면 비상구로 탈출경로를 수정한다.","JPN":"経路を修正して、相対的に個体数が少ない側面の非常口から脱出する。","ENG":"I'll change the escape route to the side emergency exit, where there are fewer of them.","TWN":"修改逃生路線，改為侵蝕體數量較少的側面緊急出口。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"지금부터 달릴 테니 떨어지지 말고 바짝 붙어라. 꼬마.","JPN":"今から走るが遅れずぴったりついてこい。ちび。","ENG":"We'll be running from here, so don't fall behind, kid.","TWN":"我們要開始跑起來。跟好，別脫隊了，小鬼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아… 알겠습니다!","JPN":"わ……わかりました！","ENG":"O-okay!","TWN":"我……知道了！"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"으…","JPN":"うう……","ENG":"Ugh...","TWN":"呃……"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"나도 돕고 싶은데, 너무 어두워서 하나도 안 보여.","JPN":"私も手伝いたいのに、暗すぎて何も見えない。","ENG":"I want to help, but it's so dark. I can't see anything.","TWN":"我也想幫忙，可是太黑了，什麼都看不見。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"아무 준비도 없이 들어와선 방해만 되고… 서윤 말처럼 난 귀찮은 애가 맞아.","JPN":"何の準備もせずに入ってきて邪魔になるだけで……シズカさんの言う通りに私はめんどくさい子だ。","ENG":"I came in without preparation and just caused trouble... Just like Seo Yoon said, I'm a troublesome kid.","TWN":"毫無準備地闖進來只會添亂……就像徐芸說的，我確實是個麻煩精。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이런, 천장이…?!","JPN":"しまった、天井が……！？","ENG":"Oh no, the ceiling...!","TWN":"該死……天花板……？！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"…카운터들, 괜찮나?","JPN":"……カウンターたち、大丈夫か？","ENG":"...Counters, are you all right?","TWN":"……各位制裁者還好嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"고, 고맙습니다.","JPN":"あ、ありがとうございます。","ENG":"Th-thank you.","TWN":"謝，謝謝你。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"감싸주신 덕에 멀쩡하지만… 아저씨는요?","JPN":"庇ってくださったのでこちらは無事ですが……おじさんは？","ENG":"Thanks to your protection, we're fine, but... what about you, sir?","TWN":"多虧了你的保護，我沒事……大叔你呢？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"흥, 떨어진 콘크리트와 강화 외골격 슈트. 어느 쪽이 더 튼튼할 것 같나?","JPN":"ふん、落ちてきたコンクリートと強化外骨格スーツ。どちらが丈夫だと思うか？","ENG":"Hmph, concrete or improved exoskeleton suit. Which one do you think is sturdier?","TWN":"哼，混凝土和強化外骨骼戰鬥服，你覺得哪個更堅固？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"잘 모르겠는데요?","JPN":"よくわかりませんけど？","ENG":"I'm not sure.","TWN":"我不知道啊。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"정답은 내일 내 등골이 좀 쑤실 예정이란 거다.","JPN":"答えは、明日背中がやや痛くなる予定だということだ。","ENG":"The answer is that my back is going to ache a bit tomorrow.","TWN":"答案是明天我的脊樑骨會有點酸痛。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"방금 상층이 무너지면서 비상탈출로가 막혔군. 다른 길을 찾아야한다.","JPN":"いま上層が崩れて非常口が塞がった。他の道を探さねばならない。","ENG":"Looks like the upper floors just collapsed and blocked the emergency exit. We need to find another way.","TWN":"剛才上層坍塌，緊急逃生通道被堵住了。我們得找其他出路。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"침식 때문에 건물 기반이 눈에 띄게 약해지고 있어요.","JPN":"侵食のせいで建物の基盤がどんどん弱くなっています。","ENG":"The building's foundation is clearly weakening due to the Corruption.","TWN":"由於侵蝕，建築明顯變得脆弱了。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"마땅한 탈출로가 없으면 무릴 해서라도 정면돌파를 하는 편이…","JPN":"脱出路がないなら無理してでも正面から突破したほうが……","ENG":"If there's no suitable escape route, it's better to force a direct breakthrough...","TWN":"沒有適合的逃脫路線時，寧可冒險也要正面突圍。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저… 저기… 서윤.","JPN":"あ……あの……シズカさん。","ENG":"Hey... um... Seo Yoon?","TWN":"我……那個……徐芸……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"반성이나 사과는 나중에! 지금은 그럴 때가 아냐.","JPN":"反省や謝罪は後にして！　今はそれどころじゃない。","ENG":"Apologies and reflections can wait! Now's not the time for that.","TWN":"反省和道歉以後再說！現在不是時候。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그게 아니라…","JPN":"そうじゃなくて……","ENG":"That's not what I meant...","TWN":"不是的……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};